sourceLocationAdd.query:
mutation InventoryConnectionLocationAdd($input: LocationAddInput!) {
  locationAdd(input: $input) {
    location {
      id
      name
      isActive
    }
    userErrors {
      field
      message
      code
    }
  }
}

